const sendTonSchema = objectType({
	toAddress: stringType().min(1).describe("Recipient TON address"),
	amount: stringType().min(1).describe("Amount of TON to send (e.g., \"1.5\" for 1.5 TON)"),
	comment: stringType().optional().describe("Optional comment/memo for the transaction")
});
const sendJettonSchema = objectType({
	toAddress: stringType().min(1).describe("Recipient TON address"),
	jettonAddress: stringType().min(1).describe("Jetton master contract address"),
	amount: stringType().min(1).describe("Amount of tokens to send in human-readable format"),
	comment: stringType().optional().describe("Optional comment/memo for the transaction")
});
const transactionMessageSchema = objectType({
	address: stringType().min(1).describe("Recipient wallet address"),
	amount: stringType().min(1).describe("Amount to transfer in nanotons"),
	stateInit: stringType().optional().describe("Initial state for deploying a new contract (Base64)"),
	payload: stringType().optional().describe("Message payload data (Base64)")
});
const sendRawTransactionSchema = objectType({
	messages: arrayType(transactionMessageSchema).min(1).describe("Array of messages to include in the transaction"),
	validUntil: numberType().optional().describe("Unix timestamp after which the transaction becomes invalid"),
	fromAddress: stringType().optional().describe("Sender wallet address")
});
function createMcpTransferTools(service) {
	return {
		send_ton: {
			description: "Send TON from the wallet to an address. Amount is in TON (e.g., \"1.5\" means 1.5 TON). Returns normalizedHash. Default flow: poll get_transaction_status until completed or failed; user can skip.",
			inputSchema: sendTonSchema,
			handler: async (args) => {
				const rawAmount = toRawAmount(args.amount, TON_DECIMALS);
				const result = await service.sendTon(args.toAddress, rawAmount, args.comment);
				if (!result.success) return {
					content: [{
						type: "text",
						text: JSON.stringify({
							success: false,
							error: result.message
						})
					}],
					isError: true
				};
				return { content: [{
					type: "text",
					text: JSON.stringify({
						success: true,
						message: result.message,
						normalizedHash: result.normalizedHash,
						details: {
							to: args.toAddress,
							amount: `${args.amount} TON`,
							comment: args.comment || null,
							normalizedHash: result.normalizedHash
						}
					}, null, 2)
				}] };
			}
		},
		send_jetton: {
			description: "Send Jettons (tokens) from the wallet to an address. Amount is in human-readable format. Returns normalizedHash. Default flow: poll get_transaction_status until completed or failed; user can skip.",
			inputSchema: sendJettonSchema,
			handler: async (args) => {
				let decimals;
				let symbol;
				try {
					const jetton = (await service.getJettons()).find((j) => j.address.toLowerCase() === args.jettonAddress.toLowerCase());
					if (jetton) {
						decimals = jetton.decimals;
						symbol = jetton.symbol;
					}
				} catch (error) {
					return {
						content: [{
							type: "text",
							text: JSON.stringify({
								success: false,
								error: `Failed to fetch jetton info: ${error instanceof Error ? error.message : "Unknown error"}`
							})
						}],
						isError: true
					};
				}
				if (decimals === void 0) return {
					content: [{
						type: "text",
						text: JSON.stringify({
							success: false,
							error: `Cannot determine decimals for jetton ${args.jettonAddress}. The token may not be in your wallet.`
						})
					}],
					isError: true
				};
				const rawAmount = toRawAmount(args.amount, decimals);
				const result = await service.sendJetton(args.toAddress, args.jettonAddress, rawAmount, args.comment);
				if (!result.success) return {
					content: [{
						type: "text",
						text: JSON.stringify({
							success: false,
							error: result.message
						})
					}],
					isError: true
				};
				return { content: [{
					type: "text",
					text: JSON.stringify({
						success: true,
						message: result.message,
						normalizedHash: result.normalizedHash,
						details: {
							to: args.toAddress,
							jettonAddress: args.jettonAddress,
							amount: `${args.amount} ${symbol || "tokens"}`,
							comment: args.comment || null,
							normalizedHash: result.normalizedHash
						}
					}, null, 2)
				}] };
			}
		},
		send_raw_transaction: {
			description: "Send a raw transaction with full control over messages. Amounts are in nanotons. Supports multiple messages. Returns normalizedHash. Default flow: poll get_transaction_status until completed or failed; user can skip.",
			inputSchema: sendRawTransactionSchema,
			handler: async (args) => {
				const result = await service.sendRawTransaction({
					messages: args.messages,
					validUntil: args.validUntil,
					fromAddress: args.fromAddress
				});
				if (!result.success) return {
					content: [{
						type: "text",
						text: JSON.stringify({
							success: false,
							error: result.message
						})
					}],
					isError: true
				};
				return { content: [{
					type: "text",
					text: JSON.stringify({
						success: true,
						message: result.message,
						normalizedHash: result.normalizedHash,
						details: {
							messageCount: args.messages.length,
							messages: args.messages.map((m) => ({
								to: m.address,
								amount: `${m.amount} nanoTON`
							})),
							normalizedHash: result.normalizedHash
						}
					}, null, 2)
				}] };
			}
		}
	};
}

